import{_ as d,H as a,f as e,i as n}from"./chunks/framework.eFU6Tutu.js";const u=JSON.parse('{"title":"映射规则","description":"","frontmatter":{},"headers":[],"relativePath":"reference/rules.md","filePath":"reference/rules.md"}'),r={name:"reference/rules.md"};function s(i,t,o,p,l,c){return a(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="映射规则" tabindex="-1">映射规则 <a class="header-anchor" href="#映射规则" aria-label="Permalink to &quot;映射规则&quot;">​</a></h1><p>本文档汇总 invnz 的所有映射规则，包括韵母分解、字根映射和 IDC 组合规则。</p><h2 id="一、韵母分解" tabindex="-1">一、韵母分解 <a class="header-anchor" href="#一、韵母分解" aria-label="Permalink to &quot;一、韵母分解&quot;">​</a></h2><p>韵母根据分解表拆分为音素序列。不在表中的韵母保持原样。</p><table tabindex="0"><thead><tr><th>韵母</th><th>音素</th><th>说明</th></tr></thead><tbody><tr><td>a</td><td>a</td><td>单韵母</td></tr><tr><td>o</td><td>o</td><td>单韵母</td></tr><tr><td>e</td><td>e</td><td>单韵母</td></tr><tr><td>i</td><td>i</td><td>单韵母</td></tr><tr><td>u</td><td>u</td><td>单韵母</td></tr><tr><td>ü</td><td>v</td><td>内部用 v 表示 ü</td></tr><tr><td>ai</td><td>ai</td><td>复合韵母</td></tr><tr><td>ei</td><td>ei</td><td></td></tr><tr><td>ao</td><td>ao</td><td></td></tr><tr><td>ou</td><td>ou</td><td></td></tr><tr><td>an</td><td>an</td><td></td></tr><tr><td>en</td><td>en</td><td></td></tr><tr><td>ang</td><td>ang</td><td></td></tr><tr><td>eng</td><td>eng</td><td></td></tr><tr><td>er</td><td>er</td><td></td></tr><tr><td>ia</td><td>i_a</td><td>介音 + 韵腹</td></tr><tr><td>ie</td><td>ie</td><td>整体音素</td></tr><tr><td>iao</td><td>i_ao</td><td></td></tr><tr><td>iu</td><td>i_ou</td><td></td></tr><tr><td>ian</td><td>ie_an</td><td>介音 + 韵尾</td></tr><tr><td>in</td><td>i_en</td><td></td></tr><tr><td>iang</td><td>i_ang</td><td></td></tr><tr><td>ing</td><td>i_eng</td><td></td></tr><tr><td>iong</td><td>iong</td><td>整体音素</td></tr><tr><td>ua</td><td>u_a</td><td></td></tr><tr><td>uo</td><td>uo</td><td></td></tr><tr><td>uai</td><td>u_ai</td><td></td></tr><tr><td>ui</td><td>u_ei</td><td></td></tr><tr><td>uan</td><td>u_an</td><td></td></tr><tr><td>un</td><td>u_en</td><td></td></tr><tr><td>uang</td><td>u_ang</td><td></td></tr><tr><td>ong</td><td>ong</td><td></td></tr><tr><td>üe</td><td>ve</td><td></td></tr><tr><td>üan</td><td>ve_an</td><td></td></tr><tr><td>ün</td><td>v_en</td><td></td></tr></tbody></table><h3 id="特殊转换" tabindex="-1">特殊转换 <a class="header-anchor" href="#特殊转换" aria-label="Permalink to &quot;特殊转换&quot;">​</a></h3><p><strong>i‑drop</strong>：当声母为 <code>j</code> <code>q</code> <code>x</code> <code>zh</code> <code>ch</code> <code>sh</code> <code>r</code> <code>z</code> <code>c</code> <code>s</code> 时，韵母中独立的 <code>i</code> 音素被省略：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ji     → j_i   （不变 — 无后续韵母）</span></span>
<span class="line"><span>jin    → j_en  （i 被省略）</span></span>
<span class="line"><span>jing   → j_eng （i 被省略）</span></span>
<span class="line"><span>xin    → x_en  （i 被省略）</span></span></code></pre></div><p><strong>bpmf + o → uo</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bo  → b_uo</span></span>
<span class="line"><span>po  → p_uo</span></span>
<span class="line"><span>mo  → m_uo</span></span>
<span class="line"><span>fo  → f_uo</span></span></code></pre></div><p><strong>jqx + u → ü</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ju   → j_v</span></span>
<span class="line"><span>qu   → q_v</span></span>
<span class="line"><span>xu   → x_v</span></span>
<span class="line"><span>juan → j_ve_an</span></span></code></pre></div><h2 id="二、声母字根映射" tabindex="-1">二、声母字根映射 <a class="header-anchor" href="#二、声母字根映射" aria-label="Permalink to &quot;二、声母字根映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>声母</th><th>字根</th><th>IDC 类型</th></tr></thead><tbody><tr><td>（零声母）</td><td>⿰丨</td><td>左右</td></tr><tr><td>b</td><td>⿱不</td><td>上下</td></tr><tr><td>p</td><td>⿱攵</td><td>上下</td></tr><tr><td>m</td><td>⿰木</td><td>左右</td></tr><tr><td>f</td><td>⿱父</td><td>上下</td></tr><tr><td>d</td><td>⿱𠂊</td><td>上下</td></tr><tr><td>t</td><td>⿰七</td><td>左右</td></tr><tr><td>n</td><td>⿱冖</td><td>上下</td></tr><tr><td>l</td><td>⿺𠃊</td><td>左下包围</td></tr><tr><td>g</td><td>⿰𠂎</td><td>左右</td></tr><tr><td>k</td><td>⿰丬</td><td>左右</td></tr><tr><td>h</td><td>⿰丩</td><td>左右</td></tr><tr><td>j</td><td>⿱几</td><td>上下</td></tr><tr><td>q</td><td>⿱七</td><td>上下</td></tr><tr><td>x</td><td>⿱西</td><td>上下</td></tr><tr><td>zh</td><td>⿱止</td><td>上下</td></tr><tr><td>ch</td><td>⿱尺</td><td>上下</td></tr><tr><td>sh</td><td>⿸尸</td><td>左上包围</td></tr><tr><td>r</td><td>⿰日</td><td>左右</td></tr><tr><td>z</td><td>⿰子</td><td>左右</td></tr><tr><td>c</td><td>⿰朿</td><td>左右</td></tr><tr><td>s</td><td>⿱四</td><td>上下</td></tr></tbody></table><h2 id="三、韵母字根映射" tabindex="-1">三、韵母字根映射 <a class="header-anchor" href="#三、韵母字根映射" aria-label="Permalink to &quot;三、韵母字根映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>音素</th><th>字根</th><th>说明</th></tr></thead><tbody><tr><td>a</td><td>八</td><td></td></tr><tr><td>i</td><td>一</td><td></td></tr><tr><td>u</td><td>五</td><td></td></tr><tr><td>v (ü)</td><td>雨</td><td></td></tr><tr><td>ai</td><td>才</td><td></td></tr><tr><td>ei</td><td>巿</td><td></td></tr><tr><td>ao</td><td>刀</td><td></td></tr><tr><td>ou</td><td>口</td><td></td></tr><tr><td>ong</td><td>工</td><td></td></tr><tr><td>ie</td><td>也</td><td>整体音素</td></tr><tr><td>ve (üe)</td><td>月</td><td>整体音素</td></tr><tr><td>er</td><td>耳</td><td></td></tr><tr><td>en</td><td>⿵冂</td><td>韵尾，上包围</td></tr><tr><td>an</td><td>⿵𰃦</td><td>韵尾，上包围</td></tr><tr><td>eng</td><td>⿹𠃌</td><td>韵尾，右上包围</td></tr><tr><td>ang</td><td>⿹勹</td><td>韵尾，右上包围</td></tr><tr><td>iong</td><td>用</td><td>整体（仅零声母）</td></tr></tbody></table><h2 id="四、idc-组合规则" tabindex="-1">四、IDC 组合规则 <a class="header-anchor" href="#四、idc-组合规则" aria-label="Permalink to &quot;四、IDC 组合规则&quot;">​</a></h2><h3 id="规则-1-韵尾包围" tabindex="-1">规则 1：韵尾包围 <a class="header-anchor" href="#规则-1-韵尾包围" aria-label="Permalink to &quot;规则 1：韵尾包围&quot;">​</a></h3><p>韵尾（en/an/eng/ang）的 IDC 包裹前一个字根：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i + en     → ⿵冂一</span></span>
<span class="line"><span>ie + an    → ⿵𰃦也</span></span>
<span class="line"><span>u + eng    → ⿹𠃌五</span></span>
<span class="line"><span>i + ang    → ⿹勹一</span></span></code></pre></div><h3 id="规则-2-声母包裹" tabindex="-1">规则 2：声母包裹 <a class="header-anchor" href="#规则-2-声母包裹" aria-label="Permalink to &quot;规则 2：声母包裹&quot;">​</a></h3><p>声母的 IDC 包裹整个韵部组合结果：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zh + ong       → ⿱止工</span></span>
<span class="line"><span>g + u + an     → ⿰𠂎⿵𰃦五</span></span>
<span class="line"><span>t + ie + an    → ⿰七⿵𰃦也</span></span></code></pre></div><h3 id="规则-3-仅有韵尾" tabindex="-1">规则 3：仅有韵尾 <a class="header-anchor" href="#规则-3-仅有韵尾" aria-label="Permalink to &quot;规则 3：仅有韵尾&quot;">​</a></h3><p>当韵部只有一个韵尾时：</p><ul><li><p><strong>声母 IDC = ⿰</strong>：韵尾包裹声母的内核</p><ul><li><code>t</code> + an → ⿵𰃦七</li><li><code>h</code> + an → ⿵𰃦丩</li></ul></li><li><p><strong>声母 IDC = ⿱ 或其他</strong>：声母包裹去 IDC 后的韵尾</p><ul><li><code>b</code> + an → ⿱不𰃦</li><li><code>d</code> + en → ⿱𠂊冂</li><li><code>l</code> + an → ⿺𠃊𰃦</li><li><code>sh</code> + an → ⿸尸𰃦</li></ul></li></ul><h3 id="规则-4-⿰x一-→-⿱x一" tabindex="-1">规则 4：⿰X一 → ⿱X一 <a class="header-anchor" href="#规则-4-⿰x一-→-⿱x一" aria-label="Permalink to &quot;规则 4：⿰X一 → ⿱X一&quot;">​</a></h3><p>当组合结果正好为 <code>⿰X一</code>（3 个 Unicode 字符）时，转为 <code>⿱X一</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⿰不一 → ⿱不一</span></span>
<span class="line"><span>⿰七一 → ⿱七一</span></span></code></pre></div><h3 id="规则-5-零声母" tabindex="-1">规则 5：零声母 <a class="header-anchor" href="#规则-5-零声母" aria-label="Permalink to &quot;规则 5：零声母&quot;">​</a></h3><p>仅当音节通过 <code>-x</code> 前缀条目匹配时，加 <code>⿰丨</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a   → -a 匹配 → ⿰丨八</span></span>
<span class="line"><span>wo  → -wo 匹配 → ⿰丨火</span></span>
<span class="line"><span>ong → -ong 匹配 → ⿰丨工</span></span></code></pre></div><h2 id="五、特殊情况" tabindex="-1">五、特殊情况 <a class="header-anchor" href="#五、特殊情况" aria-label="Permalink to &quot;五、特殊情况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>音节</th><th>处理方式</th></tr></thead><tbody><tr><td>wu</td><td>直接映射为「五」</td></tr><tr><td>yi</td><td>直接映射为「一」</td></tr><tr><td>yu</td><td>直接映射为「雨」</td></tr><tr><td>ye</td><td>直接映射为「也」</td></tr><tr><td>yue</td><td>直接映射为「月」</td></tr><tr><td>yong</td><td>直接映射为「用」</td></tr><tr><td>er</td><td>直接映射为「耳」</td></tr><tr><td>an/en/ang/eng</td><td>直接映射为韵尾字根（无 ⿰丨）</td></tr></tbody></table>`,34)])])}const g=d(r,[["render",s]]);export{u as __pageData,g as default};
